{
        Instance storage inst = _getInstance(instanceId);
        ActionEvent storage ev = inst.events[EventKey.StartEvent_A];
        require(ev.exists, "event not set");
        require(ev.state == ElementState.ENABLED, "event state not allowed");

        ev.state = ElementState.COMPLETED;
        emit ActionEventDone(instanceId, EventKey.StartEvent_A);
        inst.messages[MessageKey.RequestA].state = ElementState.ENABLED;

    }

{
        Instance storage inst = _getInstance(instanceId);
        Message storage m = inst.messages[MessageKey.RequestA];
        require(m.exists, "message not set");
        _checkParticipant(inst, m.sendParticipant);
        require(m.state == ElementState.ENABLED, "message state not allowed");

        m.fireflyTranId = fireflyTranId;
        m.state = ElementState.COMPLETED;
        emit MessageSent(instanceId, MessageKey.RequestA, fireflyTranId);
        inst.gateways[GatewayKey.DecisionA].state = ElementState.ENABLED;

    }

{
        Instance storage inst = _getInstance(instanceId);
        Message storage m = inst.messages[MessageKey.ConfirmA];
        require(m.exists, "message not set");
        _checkParticipant(inst, m.sendParticipant);
        require(m.state == ElementState.ENABLED, "message state not allowed");

        m.fireflyTranId = fireflyTranId;
        m.state = ElementState.COMPLETED;
        emit MessageSent(instanceId, MessageKey.ConfirmA, fireflyTranId);
        inst.events[EventKey.EndEvent_A].state = ElementState.ENABLED;

    }

{
        Instance storage inst = _getInstance(instanceId);
        Gateway storage g = inst.gateways[GatewayKey.DecisionA];
        require(g.exists, "gateway not set");
        require(g.state == ElementState.ENABLED, "gateway state not allowed");

        g.state = ElementState.COMPLETED;
        emit GatewayDone(instanceId, GatewayKey.DecisionA);
        if (inst.stateMemory.ApprovedA == true) {
            inst.messages[MessageKey.ConfirmA].state = ElementState.ENABLED;
        }
        else {
            inst.events[EventKey.EndEvent_A].state = ElementState.ENABLED;
        }

    }

{
        Instance storage inst = _getInstance(instanceId);
        ActionEvent storage ev = inst.events[EventKey.EndEvent_A];
        require(ev.exists, "event not set");
        require(ev.state == ElementState.ENABLED, "event state not allowed");

        ev.state = ElementState.COMPLETED;
        emit ActionEventDone(instanceId, EventKey.EndEvent_A);

    }
